import Modal from '../Modal'
import NavBar from './NavBar'

import type { ModalNavBarModalProps, ModalNavBarModalRef } from '../types'

// \u5185\u5E93\u4F7F\u7528-start
import DOMUtil from './../../../utils/DOMUtil'
// \u5185\u5E93\u4F7F\u7528-end

/* \u6D4B\u8BD5\u4F7F\u7528-start
import { DOMUtil } from 'lyrixi-mobile'
\u6D4B\u8BD5\u4F7F\u7528-end */

// NavBarModal
const NavBarModal = forwardRef<ModalNavBarModalRef, ModalNavBarModalProps>(
  (
    {
      // Status
      open,
      maskClosable,

      // Style
      safeArea,
      navBarStyle,
      navBarClassName,
      modalStyle,
      modalClassName,
      maskStyle,
      maskClassName,

      // Elements
      portal,
      title,
      okNode,
      okVisible,
      okPosition,
      cancelNode,
      cancelVisible,
      cancelPosition,
      children,

      // Events
      onCancel,
      onOk,
      onClose
    },
    ref
  ) => {
    // \u4E8B\u4EF6
    function handleCancelClick(e: MouseEvent<HTMLDivElement>) {
      e.stopPropagation()

      onCancel?.()
      onClose?.()
    }

    async function handleOkClick(e: MouseEvent<HTMLDivElement>) {
      e.stopPropagation()
      if (onOk) {
        let goOn = await onOk()
        if (goOn === false) return
      }
      onClose?.()
    }

    return (
      <Modal
        ref={ref}
        safeArea={safeArea}
        portal={portal}
        open={open}
        animation={'slideUp'}
        // Style
        maskClosable={maskClosable}
        maskClassName={DOMUtil.classNames('lyrixi-mask-navbar', maskClassName)}
        maskStyle={maskStyle}
        modalClassName={DOMUtil.classNames('lyrixi-modal-navbar', modalClassName)}
        modalStyle={modalStyle}
        // Events
        onClose={onClose}
      >
        <NavBar
          // Style
          style={navBarStyle}
          className={navBarClassName}
          // Elements
          title={title}
          okNode={okNode}
          cancelNode={cancelNode}
          okVisible={okVisible}
          okPosition={okPosition}
          cancelVisible={cancelVisible}
          cancelPosition={cancelPosition}
          // Events
          onOk={handleOkClick}
          onCancel={handleCancelClick}
        />

        {/* \u4E3B\u4F53 */}
        {children}
      </Modal>
    )
  }
)
export default NavBarModal
`},78383:function(t,e){e.Z=`// \u6839\u636E\u52A8\u753B\u5224\u5B9A\u65B9\u5411
function getClassNameByAnimation(animation: string): string {
  // \u6784\u5EFA\u52A8\u753B
  let position = ''
  switch (animation) {
    case 'slideLeft':
      position = 'lyrixi-right-middle'
      break
    case 'slideRight':
      position = 'lyrixi-left-middle'
      break
    case 'slideUp':
      position = 'lyrixi-bottom-center'
      break
    case 'slideDown':
      position = 'lyrixi-top-center'
      break
    case 'zoom':
      position = 'lyrixi-middle'
      break
    case 'fade':
      position = 'lyrixi-middle'
      break
    // Tooltip\u5F39\u7A97\u7279\u6709\u5C5E\u6027
    case 'slideUpLeft':
    case 'zoomUpLeft':
    case 'fadeUpLeft':
      position = 'lyrixi-bottom-left'
      break
    case 'slideDownLeft':
    case 'zoomDownLeft':
    case 'fadeDownLeft':
      position = 'lyrixi-top-left'
      break
    case 'slideUpRight':
    case 'zoomUpRight':
    case 'fadeUpRight':
      position = 'lyrixi-bottom-right'
      break
    case 'slideDownRight':
    case 'zoomDownRight':
    case 'fadeDownRight':
      position = 'lyrixi-top-right'
      break
    default:
      position = 'lyrixi-middle'
  }
  return position
}

export default getClassNameByAnimation
