import LocaleUtil from './../../LocaleUtil'
import Device from './../../Device'
import Message from './../../../components/Message'
// \u5185\u5E93\u4F7F\u7528-end

/* \u6D4B\u8BD5\u4F7F\u7528-start
import { Device, Message, LocaleUtil } from 'lyrixi-mobile'
\u6D4B\u8BD5\u4F7F\u7528-end */

// \u5BA2\u6237\u7AEF\u9ED8\u8BA4\u8FD4\u56DE\u63A7\u5236
async function back(delta = -1, helpers?: { closeWindow?: () => void }) {
  const { closeWindow = () => {} } = helpers || {}
  // \u8FD4\u56DE\u64CD\u4F5C\u5BF9\u8C61\u4E0E\u8FD4\u56DE\u5C42\u7EA7
  let isFromApp = String(Device.getUrlParameter('isFromApp') || '')

  if (isFromApp === '1') {
    closeWindow()
    return true
  }
  // \u8FD4\u56DE\u9996\u9875\uFF08\u5386\u53F2\u8FD4\u56DE\uFF09
  else if (isFromApp === 'home') {
    window.history.go(-1)
    return true
  }
  // \u63D0\u793A\u540E\uFF0C\u5173\u95ED\u8FD4\u56DE\uFF0C\u6216\u8005\u5386\u53F2\u8FD4\u56DE
  else if (isFromApp.indexOf('confirm-close') !== -1 || isFromApp.indexOf('confirm') !== -1) {
    // \u9ED8\u8BA4\u63D0\u793A\u4FE1\u606F
    let confirmContent = LocaleUtil.locale(
      '\u60A8\u786E\u5B9A\u8981\u79BB\u5F00\u6B64\u9875\u9762\u5417?',
      'lyrixi_2fae075cbe7ea265de0b853a3d85c46d'
    )
    // \u5730\u5740\u680F\u52A8\u6001\u63D0\u793A\u4FE1\u606F
    if (isFromApp.indexOf('confirm-close:') !== -1) {
      let newConfirmContent = isFromApp.replace('confirm-close:', '')
      if (newConfirmContent) {
        confirmContent = decodeURIComponent(decodeURIComponent(newConfirmContent))
      }
    } else if (isFromApp.indexOf('confirm:') !== -1) {
      let newConfirmContent = isFromApp.replace('confirm:', '')
      if (newConfirmContent) {
        confirmContent = decodeURIComponent(decodeURIComponent(newConfirmContent))
      }
    }

    Message.open({
      content: confirmContent,
      buttons: [
        {
          name: LocaleUtil.locale('\u53D6\u6D88', 'lyrixi_625fb26b4b3340f7872b411f401e754c') as string,
          onClick: () => {
            return true
          }
        },
        {
          name: LocaleUtil.locale('\u786E\u5B9A', 'lyrixi_38cf16f2204ffab8a6e0187070558721') as string,
          className: 'lyrixi-primary',
          onClick: () => {
            // \u63D0\u793A\u540E\u5173\u95ED\u5F53\u524D\u9875\u9762
            if (isFromApp.indexOf('confirm-close') !== -1) {
              console.log('back:confirm-close')
              closeWindow()
            }
            // \u63D0\u793A\u540E\u8FD4\u56DE\u4E0A\u4E00\u9875
            else {
              console.log('confirm')
              window.history.go(delta)
            }
            return true
          }
        }
      ]
    })
  }
  // \u8FD4\u56DE\u4E0A\u4E00\u9875
  else {
    window.history.go(delta)
  }
}

export default back
