import type { BridgeOpenLocationCoord } from './../types'

// \u5185\u5E93\u4F7F\u7528-start
import GeoUtil from './../../GeoUtil'
// \u5185\u5E93\u4F7F\u7528-end

/* \u6D4B\u8BD5\u4F7F\u7528-start
import { GeoUtil } from 'lyrixi-mobile'
\u6D4B\u8BD5\u4F7F\u7528-end */

// \u683C\u5F0F\u5316openLocation\u53C2\u6570, \u5750\u6807\u81EA\u52A8\u8F6C\u6362: \u56FD\u5185\u8F6Cgcj02, \u56FD\u5916\u8F6Cwgs84
function formatOpenLocationCoord(
  coord: BridgeOpenLocationCoord | null | undefined
): BridgeOpenLocationCoord | null | undefined {
  // \u53C2\u6570\u4E0D\u5408\u6CD5
  if (!coord?.longitude || !coord?.latitude || !coord?.type) {
    return coord
  }

  // \u662F\u5426\u5728\u4E2D\u56FD
  let isInChina = GeoUtil.isInChina([coord.longitude, coord.latitude]) === true
  coord.isInChina = isInChina

  // \u4E0D\u5728\u4E2D\u56FD
  if (!isInChina) {
    const points = GeoUtil.coordtransform(
      [coord.longitude, coord.latitude],
      coord.type,
      'wgs84'
    )
    if (!points) return coord

    return {
      ...coord,
      longitude: points[0],
      latitude: points[1],
      type: 'wgs84'
    }
  }
  // \u5728\u4E2D\u56FD
  else {
    const points = GeoUtil.coordtransform(
      [coord.longitude, coord.latitude],
      coord.type,
      'gcj02'
    )
    if (!points) return coord

    return {
      ...coord,
      longitude: points[0],
      latitude: points[1],
      type: 'gcj02'
    }
  }
}

export default formatOpenLocationCoord
